# ROBUSTNESS PHASE K — Codegen error message quality
# Manually written, not generated by testgen.py. Do not delete.
#
# Every test submits a deliberately broken diagnostics_config.yaml to
# codegen.py --dry-run and asserts:
#   (a) exit code is non-zero  (codegen must refuse, not silently proceed)
#   (b) stderr contains a specific keyword that makes the error actionable
#       (field name, value, index, or standard reference)
#
# These are the errors a first-time customer encounters. A cryptic Python
# traceback or a silent exit-0 on bad input is a support ticket. A clear
# message is self-service.
#
# Run: pytest test_robustness_K_error_quality.py -v
from __future__ import annotations

import os
import subprocess
import sys
import tempfile
import textwrap

import pytest

EDS_ROOT = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
CODEGEN  = os.path.join(EDS_ROOT, "tools", "codegen.py")

# ── Helpers ───────────────────────────────────────────────────────────────────

_VALID_BASE = textwrap.dedent("""\
    schema_version: 1
    metadata:
      ecu_name: "TestECU"
      version:  "1.0.0"
    timing:
      p2_server_max_ms:      25
      p2_star_server_max_ms: 5000
      s3_server_timeout_ms:  5000
    dids:
      - id:   "0xF190"
        name: "VehicleIdentificationNumber"
        access: [read]
        min_session: "default"
        read_security_level:  0
        write_security_level: 0
        data_length: 17
    dtcs:
      - code:        "0xC00100"
        description: "CAN bus loss"
        severity:    "check_at_next_halt"
    routines:
      - id:   "0xFF00"
        name: "SelfTest"
        min_session:    "extended"
        security_level: 0
        support:        ["start"]
""")


def _run_codegen(yaml_content: str) -> tuple[int, str]:
    """Write yaml_content to a tempfile and run codegen --dry-run. Returns (rc, stderr)."""
    with tempfile.TemporaryDirectory() as tmpdir:
        cfg_path = os.path.join(tmpdir, "config.yaml")
        out_path = os.path.join(tmpdir, "out")
        os.makedirs(out_path)
        with open(cfg_path, "w") as f:
            f.write(yaml_content)
        r = subprocess.run(
            [sys.executable, CODEGEN, "--config", cfg_path, "--out", out_path, "--dry-run"],
            capture_output=True, text=True,
        )
        return r.returncode, r.stdout + r.stderr


def _bad(patch: str) -> str:
    """Replace a line in the valid base YAML."""
    lines = _VALID_BASE.splitlines(keepends=True)
    for i, line in enumerate(lines):
        for old, new in [p.split(" -> ", 1) for p in patch.split("\n") if " -> " in p]:
            if old in line:
                lines[i] = line.replace(old, new)
    return "".join(lines)


def _assert_rejected(yaml_content: str, *keywords: str):
    rc, out = _run_codegen(yaml_content)
    assert rc != 0, (
        f"Expected exit code != 0 for bad YAML, got 0.\nOutput:\n{out}")
    lower = out.lower()
    for kw in keywords:
        assert kw.lower() in lower, (
            f"Expected keyword {kw!r} in codegen output.\nActual output:\n{out}")


# ── Sanity: good YAML exits 0 ─────────────────────────────────────────────────

class TestSanity:
    def test_valid_yaml_exits_0(self):
        rc, out = _run_codegen(_VALID_BASE)
        assert rc == 0, f"Valid YAML should exit 0.\nOutput:\n{out}"

    def test_valid_yaml_prints_dry_run_complete(self):
        rc, out = _run_codegen(_VALID_BASE)
        assert "dry run complete" in out.lower() or "config is valid" in out.lower(), (
            f"Expected dry-run success message.\nOutput:\n{out}")


# ── Class 1: Metadata errors ──────────────────────────────────────────────────

class TestMetadataErrors:
    """Missing or malformed metadata fields."""

    def test_missing_metadata_section(self):
        yaml = _VALID_BASE.replace("metadata:\n  ecu_name: \"TestECU\"\n  version:  \"1.0.0\"\n", "")
        _assert_rejected(yaml, "metadata")

    def test_missing_ecu_name(self):
        yaml = _VALID_BASE.replace('  ecu_name: "TestECU"\n', "")
        _assert_rejected(yaml, "ecu_name")

    def test_missing_version(self):
        yaml = _VALID_BASE.replace('  version:  "1.0.0"\n', "")
        _assert_rejected(yaml, "version")

    def test_schema_version_mismatch(self):
        yaml = _VALID_BASE.replace("schema_version: 1", "schema_version: 99")
        _assert_rejected(yaml, "schema_version")

    def test_schema_version_wrong_type(self):
        yaml = _VALID_BASE.replace("schema_version: 1", 'schema_version: "one"')
        _assert_rejected(yaml, "schema_version")


# ── Class 2: DID errors ───────────────────────────────────────────────────────

class TestDIDErrors:
    """Bad DID id format, missing fields, duplicate, invalid access, session, security."""

    def test_missing_dids_section(self):
        yaml = "\n".join(
            line for line in _VALID_BASE.splitlines()
            if not line.startswith("dids:") and "0xF190" not in line
            and "VehicleIdentificationNumber" not in line
            and "access: [read]" not in line
            and "min_session:" not in line
            and "read_security_level" not in line
            and "write_security_level" not in line
            and "data_length: 17" not in line
        )
        _assert_rejected(yaml, "dids")

    def test_did_id_wrong_hex_length(self):
        yaml = _VALID_BASE.replace('id:   "0xF190"', 'id:   "0xF1"')
        _assert_rejected(yaml, "0xF1", "hex")

    def test_did_id_invalid_hex_chars(self):
        yaml = _VALID_BASE.replace('id:   "0xF190"', 'id:   "0xZZZZ"')
        _assert_rejected(yaml, "0xZZZZ")

    def test_did_id_no_0x_prefix(self):
        yaml = _VALID_BASE.replace('id:   "0xF190"', 'id:   "F190"')
        _assert_rejected(yaml, "F190")

    def test_duplicate_did_ids(self):
        extra = (
            "  - id:   \"0xF190\"\n"
            "    name: \"Duplicate\"\n"
            "    access: [read]\n"
            "    min_session: \"default\"\n"
            "    read_security_level:  0\n"
            "    write_security_level: 0\n"
            "    data_length: 4\n"
        )
        yaml = _VALID_BASE.replace("dtcs:\n", extra + "dtcs:\n")
        _assert_rejected(yaml, "0xF190", "already declared")

    def test_did_reserved_id_0x0000(self):
        yaml = _VALID_BASE.replace('id:   "0xF190"', 'id:   "0x0000"')
        _assert_rejected(yaml, "0x0000", "reserved")

    def test_did_missing_name(self):
        yaml = _VALID_BASE.replace('    name: "VehicleIdentificationNumber"\n', "")
        _assert_rejected(yaml, "name")

    def test_did_missing_access(self):
        yaml = _VALID_BASE.replace("    access: [read]\n", "")
        _assert_rejected(yaml, "access")

    def test_did_invalid_access_value(self):
        yaml = _VALID_BASE.replace("access: [read]", "access: [execute]")
        _assert_rejected(yaml, "execute")

    def test_did_unknown_min_session(self):
        yaml = _VALID_BASE.replace('min_session: "default"', 'min_session: "factory"')
        _assert_rejected(yaml, "factory")

    def test_did_read_security_level_out_of_range(self):
        yaml = _VALID_BASE.replace("read_security_level:  0", "read_security_level: 300")
        _assert_rejected(yaml, "read_security_level", "255")

    def test_did_data_length_zero(self):
        yaml = _VALID_BASE.replace("data_length: 17", "data_length: 0")
        _assert_rejected(yaml, "data_length")

    def test_did_data_length_over_max(self):
        yaml = _VALID_BASE.replace("data_length: 17", "data_length: 9999")
        _assert_rejected(yaml, "data_length", "4095")

    def test_write_did_missing_data_length(self):
        yaml = textwrap.dedent("""\
            schema_version: 1
            metadata:
              ecu_name: "TestECU"
              version:  "1.0.0"
            timing:
              p2_server_max_ms:      25
              p2_star_server_max_ms: 5000
              s3_server_timeout_ms:  5000
            dids:
              - id:   "0xF187"
                name: "SparePartNumber"
                access: [read, write]
                min_session: "extended"
                read_security_level:  0
                write_security_level: 1
        """)
        _assert_rejected(yaml, "data_length", "REQ-SAFE-006")


# ── Class 3: DTC errors ───────────────────────────────────────────────────────

class TestDTCErrors:
    """Bad DTC code format, duplicate, missing fields."""

    def test_dtc_code_wrong_hex_length(self):
        yaml = _VALID_BASE.replace('code:        "0xC00100"', 'code:        "0xC001"')
        _assert_rejected(yaml, "0xC001", "6-digit")

    def test_dtc_code_missing_0x_prefix(self):
        yaml = _VALID_BASE.replace('code:        "0xC00100"', 'code:        "C00100"')
        _assert_rejected(yaml, "C00100")

    def test_dtc_code_invalid_chars(self):
        yaml = _VALID_BASE.replace('code:        "0xC00100"', 'code:        "0xZZZZZZ"')
        _assert_rejected(yaml, "0xZZZZZZ")

    def test_dtc_missing_code_field(self):
        yaml = _VALID_BASE.replace(
            '  - code:        "0xC00100"\n    description: "CAN bus loss"\n',
            '  - description: "CAN bus loss"\n',
        )
        _assert_rejected(yaml, "code")

    def test_duplicate_dtc_codes(self):
        extra = (
            "  - code:        \"0xC00100\"\n"
            "    description: \"Duplicate DTC\"\n"
            "    severity:    \"check_at_next_halt\"\n"
        )
        yaml = _VALID_BASE.replace("routines:\n", extra + "routines:\n")
        _assert_rejected(yaml, "0xC00100", "already declared")


# ── Class 4: Timing errors ────────────────────────────────────────────────────

class TestTimingErrors:
    """p2 > p2*, non-positive values."""

    def test_p2_greater_than_p2_star(self):
        yaml = _VALID_BASE.replace(
            "p2_server_max_ms:      25",
            "p2_server_max_ms:      9999",
        )
        _assert_rejected(yaml, "p2_server_max_ms", "p2_star")

    def test_p2_zero(self):
        yaml = _VALID_BASE.replace("p2_server_max_ms:      25", "p2_server_max_ms: 0")
        _assert_rejected(yaml, "p2_server_max_ms")

    def test_timing_wrong_type(self):
        yaml = _VALID_BASE.replace("p2_server_max_ms:      25", 'p2_server_max_ms: "fast"')
        _assert_rejected(yaml, "p2_server_max_ms")


# ── Class 5: Routine errors ───────────────────────────────────────────────────

class TestRoutineErrors:
    """Bad routine id format, duplicate."""

    def test_routine_id_wrong_hex_length(self):
        yaml = _VALID_BASE.replace('id:   "0xFF00"', 'id:   "0xFF"')
        _assert_rejected(yaml, "0xFF", "hex")

    def test_routine_id_invalid_chars(self):
        yaml = _VALID_BASE.replace('id:   "0xFF00"', 'id:   "0xGGGG"')
        _assert_rejected(yaml, "0xGGGG")

    def test_duplicate_routine_ids(self):
        extra = (
            "  - id:   \"0xFF00\"\n"
            "    name: \"DuplicateRoutine\"\n"
            "    min_session:    \"extended\"\n"
            "    security_level: 0\n"
            "    support:        [\"start\"]\n"
        )
        yaml = _VALID_BASE + extra
        _assert_rejected(yaml, "0XFF00", "already declared")


# ── Class 6: YAML parse and structural errors ─────────────────────────────────

class TestParseErrors:
    """Broken YAML syntax, empty file, non-mapping root."""

    def test_invalid_yaml_syntax(self):
        _assert_rejected("dids: [\nunclosed bracket", "yaml", "parse")

    def test_empty_file(self):
        _assert_rejected("", "mapping")

    def test_non_mapping_root(self):
        _assert_rejected("- this\n- is\n- a list\n", "mapping")
